const item = $input.item.json;

// Generate unique ticket ID (URL-safe, 8 chars)
const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
let suffix = '';
for (let i = 0; i < 8; i++) {
  suffix += chars[Math.floor(Math.random() * chars.length)];
}
const ticketId = 'TKT-' + suffix;

const issuedDate = new Date().toLocaleDateString('en-US', {
  year: 'numeric', month: 'long', day: 'numeric'
});

const ticketTier = item['Ticket Tier'] || 'General Admission';

// Tier badge for the PDF template and email
const tierBadge = ticketTier === 'VIP' ? 'VIP'
  : ticketTier === 'Backstage Pass' ? 'BACKSTAGE'
  : 'GENERAL';

// Tier accent colour used in the confirmation email
const tierColor = ticketTier === 'VIP' ? '#7B2FBE'
  : ticketTier === 'Backstage Pass' ? '#C0392B'
  : '#0f3460';

// ⚠️ Replace 123456 with your PDF Generator API template ID.
// The template should include a QR Code component whose data is set to {{ ticket_id }}.
const TEMPLATE_ID = 1615251;

return [{
  json: {
    ticketId,
    attendeeName:  item['Full Name'],
    attendeeEmail: item['Email Address'],
    eventName:     item['Event Name'],
    venue:         item['Venue'],
    eventDate:     item['Event Date'],
    seatNumber:    item['Seat Number'],
    ticketTier,
    tierBadge,
    tierColor,
    issuedDate,
    emailSubject:  `🎫 Your ${ticketTier} Ticket: ${item['Event Name']} — ${ticketId}`,
    templateId:    TEMPLATE_ID,
    outputName:    `concert-ticket-${ticketId}`,
    // Variables passed to the PDF Generator API template.
    // Map each one to the corresponding component in your template editor.
    templateData: {
      ticket_id:     ticketId,
      attendee_name: item['Full Name'],
      event_name:    item['Event Name'],
      venue:         item['Venue'],
      event_date:    item['Event Date'],
      seat_number:   item['Seat Number'],
      ticket_tier:   tierBadge,
      issued_date:   issuedDate
    }
  }
}];

const pdfData    = $input.item.json;
const t          = $('Prepare Ticket Data').item.json;

// URL returned by PDF Generator API (documentOutput: url)
const pdfUrl = pdfData.response || '';

// Tier-specific header colour
const headerColor = t.tierColor || '#0f3460';

const emailHtml = ''
  + '<!DOCTYPE html><html><body style="margin:0;padding:0;background:#f4f4f8;font-family:Arial,sans-serif">'
  + '<table width="100%" cellpadding="0" cellspacing="0" style="padding:24px 0"><tr><td align="center">'
  + '<table width="600" cellpadding="0" cellspacing="0" style="background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 4px 24px rgba(0,0,0,0.12)">'

  // Header
  + '<tr><td style="background:' + headerColor + ';padding:36px 30px;text-align:center">'
  + '<div style="font-size:44px;line-height:1">🎵</div>'
  + '<h1 style="color:#fff;margin:10px 0 4px;font-size:24px;font-weight:700">Your Concert Ticket</h1>'
  + '<span style="display:inline-block;background:rgba(255,255,255,0.2);color:#fff;padding:4px 18px;border-radius:20px;font-size:11px;letter-spacing:2px;font-weight:700;margin-top:6px">'
  + t.tierBadge
  + '</span>'
  + '</td></tr>'

  // Body
  + '<tr><td style="padding:32px 40px">'
  + '<p style="font-size:16px;color:#333;margin:0 0 10px">Hi <strong>' + t.attendeeName + '</strong>,</p>'
  + '<p style="color:#555;line-height:1.7;margin:0 0 24px">Your <strong>' + t.ticketTier + '</strong> ticket is confirmed! Your personalized PDF — complete with a unique entry QR code — is ready to download.</p>'

  // Event card
  + '<table width="100%" cellpadding="0" cellspacing="0" style="border:2px dashed ' + headerColor + ';border-radius:10px;margin-bottom:24px"><tr><td style="padding:22px">'
  + '<h2 style="color:' + headerColor + ';margin:0 0 14px;font-size:19px">🎸 ' + t.eventName + '</h2>'
  + '<p style="margin:6px 0;color:#555;font-size:14px">📍 <strong>Venue:</strong> ' + t.venue + '</p>'
  + '<p style="margin:6px 0;color:#555;font-size:14px">📅 <strong>Date:</strong> ' + t.eventDate + '</p>'
  + '<p style="margin:6px 0;color:#555;font-size:14px">💺 <strong>Seat:</strong> ' + t.seatNumber + '</p>'
  + '<p style="margin:6px 0;color:#555;font-size:14px">🎫 <strong>Ticket ID:</strong> <code style="background:#f0f0f0;padding:2px 7px;border-radius:4px;font-size:13px">' + t.ticketId + '</code></p>'
  + '</td></tr></table>'

  // Download button
  + '<table width="100%" cellpadding="0" cellspacing="0"><tr><td align="center" style="padding-bottom:24px">'
  + '<a href="' + pdfUrl + '" style="background:' + headerColor + ';color:#fff;padding:14px 44px;border-radius:8px;text-decoration:none;font-size:15px;font-weight:700;display:inline-block">📄 Download PDF Ticket</a>'
  + '</td></tr></table>'

  + '<p style="color:#999;font-size:12px;text-align:center;margin:0 0 4px">Your PDF contains a unique QR code for venue entry.</p>'
  + '<p style="color:#bbb;font-size:11px;text-align:center;margin:0">Please have it ready — printed or on your phone.</p>'
  + '</td></tr>'

  // Footer
  + '<tr><td style="background:#f8f8f8;padding:16px 30px;text-align:center;border-top:1px solid #eee">'
  + '<p style="color:#bbb;font-size:11px;margin:0">PDF ticket generated with <a href="https://pdfgeneratorapi.com" style="color:' + headerColor + ';text-decoration:none">PDF Generator API</a> &bull; Automated by <a href="https://n8n.io" style="color:' + headerColor + ';text-decoration:none">n8n</a></p>'
  + '</td></tr>'
  + '</table></td></tr></table></body></html>';

return [{
  json: {
    attendeeEmail: t.attendeeEmail,
    emailSubject:  t.emailSubject,
    emailHtml,
    pdfUrl,
    ticketId:  t.ticketId,
    eventName: t.eventName,
    tierBadge: t.tierBadge
  }
}];
